def check_inputs(ftp_config, db_connection, api_key, monitoring_platform_url, alert_recipients):
    errors = []
    if not ftp_config:
        errors.append('FTP配置信息不能为空')
    if not db_connection:
        errors.append('数据库连接字符串不能为空')
    if not api_key:
        errors.append('API密钥不能为空')
    if not monitoring_platform_url:
        errors.append('监控平台URL不能为空')

    if errors:
        return {'valid': False, 'errors': errors}
    else:
        return {'valid': True, 'alert_recipients': alert_recipients or ''}
